CREATE INDEX idx_follow_following_id_created_at
    ON maum.follow (following_id, created_at DESC);

-- 복합 인덱스로 커버링 인덱스 효과: filesort 제거
-- 예상 개선: 인덱스 스캔 시간 30ms -> 5ms
```

